+    }
+
+    /// Run the server loop
+    pub fn run(self: *Self) !void {
+        std.debug.print("\nLanceQL Server running at http://{s}:{}\n", .{ self.host, self.port });
+        switch (self.mode) {
+            .folder => {
+                std.debug.print("Mode: folder browser\n", .{});
+                if (self.folder_path) |path| {
+                    std.debug.print("Folder: {s}\n", .{path});
+                }
+            },
+            .single_file => {
