+                    std.debug.print("Serving: {s}\n", .{path});
+                }
+            },
+            .config => {
+                std.debug.print("Mode: config builder\n", .{});
+            },
+        }
+        std.debug.print("Press Ctrl+C to stop\n\n", .{});
