+        .var_pop => "VAR_POP",
+        .median => "MEDIAN",
+        .percentile => "PERCENTILE",
+        .count_distinct => "COUNT_DISTINCT",
+        .first => "FIRST",
+        .last => "LAST",
+        .group_concat => "GROUP_CONCAT",
+        .array_agg => "ARRAY_AGG",
+        .string_agg => "STRING_AGG",
+        .bit_and => "BIT_AND",
+        .bit_or => "BIT_OR",
+        .bit_xor => "BIT_XOR",
+        .bool_and => "BOOL_AND",
+        .bool_or => "BOOL_OR",
+        .any_value => "ANY_VALUE",
+        .corr => "CORR",
+        .covar_pop => "COVAR_POP",
+        .covar_samp => "COVAR_SAMP",
+        .regr_avgx => "REGR_AVGX",
+        .regr_avgy => "REGR_AVGY",
