+        // Find "fields" array
+        const fields_start = std.mem.indexOf(u8, schema_json, "\"fields\"");
+        if (fields_start == null) return;
+
+        const array_start = std.mem.indexOfPos(u8, schema_json, fields_start.?, "[");
+        if (array_start == null) return;
